sql:
SELECT server_id, server_name, server_type, os_id 
FROM servers 
WHERE server_status = 'Active';

SELECT servers.server_name, servers.last_seen, operating_systems.os_name
FROM servers
INNER JOIN operating_systems ON servers.os_id = operating_systems.os_id;

SELECT server_name, server_updated_date
FROM servers
WHERE server_updated_date = (SELECT MAX(server_updated_date) FROM servers);

external_knowledge:
- 'beacons in the sea of production' refers to servers in the 'production' environment; 
- 'lain dormant for over a month' means the servers have not been updated in the last month or have never been updated; 
- 'awaiting the tide of an update' represents the condition where the servers need to be updated.

sql:
SELECT COUNT(*) AS total_servers
FROM servers
INNER JOIN server_data_center ON servers.server_id = server_data_center.server_id;

SELECT server_type, AVG(strftime('%J', 'now') - strftime('%J', server_created_date)) AS avg_age_days
FROM servers
GROUP BY server_type;

SELECT server_id, update_date
FROM server_updates
WHERE update_date = (SELECT MAX(update_date) FROM server_updates);

SELECT s.server_name, sc.config_key, sc.config_value
FROM servers s
JOIN server_configurations sc ON s.server_id = sc.server_id;

external_knowledge:
- Facilities refer to data centers;
- Warning types refer to alert types;
- The frequency of reports refers to the count of alerts.

- "Beacon lights" is a metaphor for servers;
- "Shone under the banner of Apache" refers to servers of type 'apache';
- "Condition... standing tall" is a metaphor for the current status of servers;
- "Ranked from A to Z in the garden of server names" refers to the alphabetical order by server names.

- "guide them" refers to the operating system used by the servers;
- "ranges of the network paths they tread" refers to the netblock range associated with each server;
- "citadels where they reside" refers to the data centers housing the servers.

sql:
SELECT servers.server_name, netblocks.netblock_owner 
FROM servers 
JOIN netblocks ON servers.netblock_id = netblocks.netblock_id;
